import java.io.*;

public class CommandInjectionSecure {
    public static void main(String[] args) {
        try {
            if (args.length < 1) {
                System.out.println("Usage: java CommandInjectionSecure <input>");
                return;
            }

            // Sanitize user input by only allowing alphanumeric characters
            String userInput = args[0].replaceAll("[^a-zA-Z0-9]", "");

            // Constructing the command to be executed with sanitized user input
            ProcessBuilder processBuilder = new ProcessBuilder("echo", userInput);

            // Start the process and read its output
            Process process = processBuilder.start();
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));

            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
